import { Component } from '@angular/core';
import { AuthService } from '../../../core/services/auth.service';

@Component({
  selector: 'app-topbar',
  templateUrl: './topbar.component.html'
})
export class TopbarComponent {
  constructor(public auth: AuthService) {}
  get initials(): string {
    const a = this.auth.auth;
    return a ? `${a.firstName[0]}${a.lastName[0]}` : 'U';
  }
  get title(): string { return ''; }
  get roleLabel(): string {
    const m: any = { PROJECT_MANAGER:'Project Manager', DEPARTMENT_HEAD:'Dept Head', TEAM_LEAD:'Team Lead', EMPLOYEE:'Employee' };
    return m[this.auth.userRole] || this.auth.userRole;
  }
}
<div class="topbar">
  <div class="topbar-left">
    <div class="page-breadcrumb">{{ title }}</div>
  </div>
  <div class="topbar-right">
    <div class="topbar-user" [routerLink]="['/employees', auth.userId]">
      <div class="avatar avatar-sm">{{ initials }}</div>
      <div class="topbar-user-info">
        <div class="topbar-name">{{ auth.auth?.firstName }} {{ auth.auth?.lastName }}</div>
        <div class="topbar-role">{{ roleLabel }}</div>
      </div>
    </div>
  </div>
</div>
